import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

describe("parseQuery", () => {
  describe("leading '?'", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses fine without a leading '?'", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("only strips the first '?' — a later '?' is part of the data", () => {
      expect(parseQuery("?a=1?2")).toEqual({ a: "1?2" });
    });

    it("treats a lone '?' as an empty query", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("keeps a leading '?' when it is a percent-encoded value, not a literal", () => {
      // "%3F" is an encoded '?', so nothing is stripped.
      expect(parseQuery("%3Fa=1")).toEqual({ "?a": "1" });
    });
  });

  describe("empty input", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns a plain object", () => {
      expect(typeof parseQuery("")).toBe("object");
      expect(parseQuery("")).toEqual({});
    });
  });

  describe("pair separation and empty segments", () => {
    it("separates pairs on '&'", () => {
      expect(parseQuery("a=1&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips empty segments between '&'", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips a leading empty segment", () => {
      expect(parseQuery("&a=1")).toEqual({ a: "1" });
    });

    it("skips a trailing empty segment", () => {
      expect(parseQuery("a=1&")).toEqual({ a: "1" });
    });

    it("skips runs of consecutive separators", () => {
      expect(parseQuery("&&&a=1&&&b=2&&&")).toEqual({ a: "1", b: "2" });
    });

    it("returns an empty object when only separators are present", () => {
      expect(parseQuery("&&&")).toEqual({});
    });
  });

  describe("single occurrence -> string value", () => {
    it("maps a key that appears once to its string value", () => {
      expect(parseQuery("name=alice")).toEqual({ name: "alice" });
    });

    it("keeps values as strings, not numbers", () => {
      const result = parseQuery("n=42");
      expect(result.n).toBe("42");
      expect(typeof result.n).toBe("string");
    });

    it("handles an empty value after '='", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });
  });

  describe("repeated keys -> array of values", () => {
    it("collects two occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("collects three or more occurrences in order of appearance", () => {
      expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
    });

    it("preserves order even when occurrences are not adjacent", () => {
      expect(parseQuery("a=1&b=x&a=2")).toEqual({ a: ["1", "2"], b: "x" });
    });

    it("groups repeated bare keys into an array of empty strings", () => {
      expect(parseQuery("flag&flag")).toEqual({ flag: ["", ""] });
    });

    it("mixes bare and valued occurrences of the same key", () => {
      expect(parseQuery("a&a=2")).toEqual({ a: ["", "2"] });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("handles multiple distinct bare keys", () => {
      expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
    });

    it("treats 'a=' and a bare 'a' both as empty-string values", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
      expect(parseQuery("a")).toEqual({ a: "" });
    });
  });

  describe("'=' handling within a segment", () => {
    it("splits on the first '=' only, keeping later '=' in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("allows an empty key when a segment starts with '='", () => {
      expect(parseQuery("=v")).toEqual({ "": "v" });
    });
  });

  describe("'+' decodes to a space", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=c+d")).toEqual({ a: "c d" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("a+b=c")).toEqual({ "a b": "c" });
    });

    it("decodes '+' in both key and value at once", () => {
      expect(parseQuery("a+b=c+d")).toEqual({ "a b": "c d" });
    });

    it("decodes '+' in a bare key", () => {
      expect(parseQuery("a+b")).toEqual({ "a b": "" });
    });
  });

  describe("percent-decoding", () => {
    it("percent-decodes values", () => {
      expect(parseQuery("a=%20")).toEqual({ a: " " });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("%61=1")).toEqual({ a: "1" });
    });

    it("decodes multi-byte UTF-8 sequences", () => {
      // %E2%9C%93 is the checkmark character.
      expect(parseQuery("x=%E2%9C%93")).toEqual({ x: "✓" });
    });

    it("decodes an encoded '&' inside a value rather than splitting on it", () => {
      expect(parseQuery("a=1%262")).toEqual({ a: "1&2" });
    });

    it("decodes an encoded '=' inside a value", () => {
      expect(parseQuery("a=%3D")).toEqual({ a: "=" });
    });

    it("replaces '+' with a space before percent-decoding", () => {
      // "%2B" survives as a literal '+', while a raw '+' becomes a space.
      expect(parseQuery("a=%2B+b")).toEqual({ a: "+ b" });
    });
  });

  describe("malformed percent-encoding never throws", () => {
    it("uses the raw value when decoding fails", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("uses the raw value for an incomplete escape", () => {
      expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
    });

    it("uses the raw key when key decoding fails", () => {
      expect(parseQuery("%GG=1")).toEqual({ "%GG": "1" });
    });

    it("still applies '+' replacement to a token that fails to decode", () => {
      // "%" cannot decode, but the '+' is already a space by then.
      expect(parseQuery("a=%+b")).toEqual({ a: "% b" });
    });

    it("does not throw on a fully malformed query string", () => {
      expect(() => parseQuery("%&%=%&=%zz")).not.toThrow();
    });
  });

  describe("combined behaviors", () => {
    it("handles a realistic query string with all features", () => {
      expect(parseQuery("?q=hello+world&tag=a&tag=b&flag&raw=100%25")).toEqual({
        q: "hello world",
        tag: ["a", "b"],
        flag: "",
        raw: "100%",
      });
    });
  });
});

